import{_ as e,o as t,c as s,a2 as n}from"./chunks/framework.DRBHoC6Q.js";const b=JSON.parse('{"title":"今日老板要拍板模块 MVP 技术方案初稿","description":"","frontmatter":{},"headers":[],"relativePath":"modules/boss-decision.md","filePath":"modules/boss-decision.md","lastUpdated":1783323851000}'),d={name:"modules/boss-decision.md"};function i(l,a,p,r,o,c){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="今日老板要拍板模块-mvp-技术方案初稿" tabindex="-1">今日老板要拍板模块 MVP 技术方案初稿 <a class="header-anchor" href="#今日老板要拍板模块-mvp-技术方案初稿" aria-label="Permalink to &quot;今日老板要拍板模块 MVP 技术方案初稿&quot;">​</a></h1><p>文档版本：V0.1<br> 状态：讨论稿，升级阈值和处理选项待产品与财务确认<br> 目标读者：产品、财务、后端开发、前端开发和测试人员</p><h2 id="_1-模块目标" tabindex="-1">1. 模块目标 <a class="header-anchor" href="#_1-模块目标" aria-label="Permalink to &quot;1. 模块目标&quot;">​</a></h2><p>“今日老板要拍板”不是独立预测模型，也不是普通风险列表。它承接其他规则引擎中无法按既定规则直接处理、必须由老板在多个业务方案中作出选择的升级事件。</p><p>模块需要回答：</p><ul><li>什么事情需要老板处理；</li><li>为什么升级到老板；</li><li>会影响多少金额、在哪一天产生影响；</li><li>老板可以选择哪些处理方案；</li><li>老板最终选择了什么；</li><li>决策是否已经完成。</li></ul><h2 id="_2-mvp-范围" tabindex="-1">2. MVP 范围 <a class="header-anchor" href="#_2-mvp-范围" aria-label="Permalink to &quot;2. MVP 范围&quot;">​</a></h2><h3 id="_2-1-本期实现" tabindex="-1">2.1 本期实现 <a class="header-anchor" href="#_2-1-本期实现" aria-label="Permalink to &quot;2.1 本期实现&quot;">​</a></h3><ul><li>接收回款风险和付款建议两类升级事件；</li><li>使用确定性规则判断是否需要老板介入；</li><li>保存事件来源、影响、证据、可选方案和处理状态；</li><li>提供“查看依据”和“AI 解释原因”；</li><li>提供事件类型对应的真实处理按钮；</li><li>保存老板选择、意见和决定时间；</li><li>来源风险解除时自动关闭尚未处理的事件。</li></ul><h3 id="_2-2-本期不实现" tabindex="-1">2.2 本期不实现 <a class="header-anchor" href="#_2-2-本期不实现" aria-label="Permalink to &quot;2.2 本期不实现&quot;">​</a></h3><ul><li>30 / 60 / 90 天现金流缺口单独生成第三类拍板事件；</li><li>独立的风险责任追踪首页模块；</li><li>“生成动作”按钮；</li><li>“老板复盘”功能；</li><li>由 AI 决定是否升级或替老板作出选择；</li><li>自动付款、自动催收或其他不可逆业务操作。</li></ul><h2 id="_3-事件来源" tabindex="-1">3. 事件来源 <a class="header-anchor" href="#_3-事件来源" aria-label="Permalink to &quot;3. 事件来源&quot;">​</a></h2><p>MVP 只接受两个来源：</p><h3 id="_3-1-回款风险" tabindex="-1">3.1 回款风险 <a class="header-anchor" href="#_3-1-回款风险" aria-label="Permalink to &quot;3.1 回款风险&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应收款 + 实际回款</span></span>
<span class="line"><span>→ 回款风险引擎</span></span>
<span class="line"><span>→ 命中老板升级条件</span></span>
<span class="line"><span>→ 老板拍板事件</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_3-2-付款建议" tabindex="-1">3.2 付款建议 <a class="header-anchor" href="#_3-2-付款建议" aria-label="Permalink to &quot;3.2 付款建议&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>计划支出 + 90 天现金流预测</span></span>
<span class="line"><span>→ 付款建议引擎</span></span>
<span class="line"><span>→ payment_assessment.decision = boss_review</span></span>
<span class="line"><span>→ 老板拍板事件</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>30 / 60 / 90 天现金流结果作为两类事件的计算依据和影响证据，不单独生成事件。这样可以避免同一个现金缺口同时产生“现金缺口事件”“回款事件”和“付款事件”。</p><h2 id="_4-统一升级原则" tabindex="-1">4. 统一升级原则 <a class="header-anchor" href="#_4-统一升级原则" aria-label="Permalink to &quot;4. 统一升级原则&quot;">​</a></h2><p>只有同时满足以下含义时才进入老板拍板：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>存在明确业务风险</span></span>
<span class="line"><span>且系统无法在既定规则内直接给出可执行处理</span></span>
<span class="line"><span>且需要老板在多个业务方案中作出选择</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>以下情况不应升级老板：</p><ul><li>系统已有明确处理规则；</li><li>普通责任人可以自行完成；</li><li>只是资料缺失或审批未完成；</li><li>只是展示正常、临期或轻度风险；</li><li>AI 认为“可能重要”，但没有命中确定性升级规则。</li></ul><h2 id="_5-回款风险升级规则" tabindex="-1">5. 回款风险升级规则 <a class="header-anchor" href="#_5-回款风险升级规则" aria-label="Permalink to &quot;5. 回款风险升级规则&quot;">​</a></h2><p>满足任一条件时，回款风险进入老板拍板：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>逾期天数 &gt;= 30 天</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>已经逾期且未回金额 &gt;= 1,000,000 元</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>对应关系：</p><table tabindex="0"><thead><tr><th>回款状态</th><th>处理方式</th><th>是否升级</th></tr></thead><tbody><tr><td>未来 2 天内临期</td><td>责任人正常关注</td><td>否</td></tr><tr><td>逾期 1～29 天且未回金额低于 100 万</td><td>责任人继续跟进</td><td>否</td></tr><tr><td>逾期达到 30 天</td><td>需要老板选择处理强度</td><td>是</td></tr><tr><td>已逾期且未回金额达到 100 万</td><td>需要老板决定是否升级催收</td><td>是</td></tr><tr><td>已全部回款</td><td>风险解除</td><td>否；已有待处理事件自动关闭</td></tr></tbody></table><p>MVP 中红色回款风险等同于老板升级边界。阈值由规则参数管理，不得散落在页面代码中。</p><h2 id="_6-付款建议升级规则" tabindex="-1">6. 付款建议升级规则 <a class="header-anchor" href="#_6-付款建议升级规则" aria-label="Permalink to &quot;6. 付款建议升级规则&quot;">​</a></h2><p>付款建议只有同时满足以下条件时进入老板拍板：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>付款资格检查通过</span></span>
<span class="line"><span>且 approval_status = approved</span></span>
<span class="line"><span>且 rigidity = rigid</span></span>
<span class="line"><span>且支付后产生或扩大现金缺口</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>对应关系：</p><table tabindex="0"><thead><tr><th>付款评估结果</th><th>处理方式</th><th>是否升级</th></tr></thead><tbody><tr><td>资料不完整</td><td>补充依据</td><td>否</td></tr><tr><td>审批未完成</td><td>继续审批</td><td>否</td></tr><tr><td>支付后不产生或扩大缺口</td><td>建议可付</td><td>否</td></tr><tr><td>可延后支出导致缺口</td><td>建议暂缓</td><td>否</td></tr><tr><td>刚性支出导致缺口</td><td>系统不能直接决定不付</td><td>是</td></tr><tr><td>支出已取消</td><td>排除</td><td>否；已有待处理事件自动关闭</td></tr></tbody></table><h2 id="_7-事件生成与幂等" tabindex="-1">7. 事件生成与幂等 <a class="header-anchor" href="#_7-事件生成与幂等" aria-label="Permalink to &quot;7. 事件生成与幂等&quot;">​</a></h2><p>建议新增 <code>decision_event</code> 表保存老板拍板事件。</p><p>每个来源先生成稳定的 <code>business_key</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>回款事件：receivable_risk:{receivable_no}</span></span>
<span class="line"><span>付款事件：payment_assessment:{expense_no}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这里使用财务模板中的稳定业务编号，而不是数据库行 UUID。每次全量导入都会生成新的数据库行 UUID，若使用 UUID，同一笔业务跨批次会被误判为新事件。</p><p>同一 <code>business_key</code> 同时最多存在一个 <code>pending</code> 事件。事件本身使用风险周期号生成 <code>event_key</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>event_key = business_key + risk_cycle_no</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>风险持续存在期间，每日重算只更新当前事件；风险解除后再次出现，<code>risk_cycle_no</code> 加一并创建新的事件。统计日期不得直接作为风险周期标识，否则会导致同一风险每天生成一张新卡片。</p><p>当同一来源重复运行规则时：</p><ul><li>已存在未处理事件：更新影响金额、日期和证据，不重复创建；</li><li>已存在已决定事件且出现新的独立风险周期：创建新事件；</li><li>来源风险已经解除：自动关闭未处理事件，并记录关闭原因；</li><li>规则版本变化：保留旧事件历史，新结果按新规则版本处理。</li></ul><h2 id="_8-决策事件表" tabindex="-1">8. 决策事件表 <a class="header-anchor" href="#_8-决策事件表" aria-label="Permalink to &quot;8. 决策事件表&quot;">​</a></h2><p><code>decision_event</code> 建议包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>id</code></td><td>主键</td></tr><tr><td><code>business_key</code></td><td>来源业务键，同一来源只允许一个待处理事件</td></tr><tr><td><code>event_key</code></td><td>业务键与风险周期组成的唯一事件键</td></tr><tr><td><code>risk_cycle_no</code></td><td>同一业务来源第几次进入升级状态</td></tr><tr><td><code>event_type</code></td><td><code>receivable_risk</code> / <code>payment_assessment</code></td></tr><tr><td><code>source_id</code></td><td>来源风险或付款评估标识</td></tr><tr><td><code>source_task_id</code></td><td>可选，关联已有风险任务</td></tr><tr><td><code>title</code></td><td>老板可读标题</td></tr><tr><td><code>risk_level</code></td><td>事件风险等级</td></tr><tr><td><code>impact_amount</code></td><td>主要影响金额</td></tr><tr><td><code>impact_date</code></td><td>主要影响日期</td></tr><tr><td><code>reason_codes</code></td><td>命中的结构化升级原因</td></tr><tr><td><code>evidence_snapshot</code></td><td>生成事件时的关键计算证据</td></tr><tr><td><code>allowed_options</code></td><td>该事件允许选择的处理方案</td></tr><tr><td><code>status</code></td><td>pending/decided/closed</td></tr><tr><td><code>selected_option</code></td><td>老板最终选择</td></tr><tr><td><code>decision_note</code></td><td>老板意见</td></tr><tr><td><code>decided_by</code></td><td>决策人</td></tr><tr><td><code>decided_at</code></td><td>决策时间</td></tr><tr><td><code>closed_reason</code></td><td>自动或人工关闭原因</td></tr><tr><td><code>import_batch_id</code></td><td>数据批次</td></tr><tr><td><code>rule_version</code></td><td>规则版本</td></tr><tr><td><code>version</code></td><td>乐观锁版本</td></tr><tr><td><code>created_at</code> / <code>updated_at</code></td><td>创建和更新时间</td></tr></tbody></table><p>核心判断、金额、日期、原因代码和证据快照由规则引擎写入。AI 不得修改这些字段。</p><h2 id="_9-页面展示" tabindex="-1">9. 页面展示 <a class="header-anchor" href="#_9-页面展示" aria-label="Permalink to &quot;9. 页面展示&quot;">​</a></h2><p>首页只展示：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>status = pending</span></span>
<span class="line"><span>且 event_type 属于 receivable_risk / payment_assessment</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>每张事件卡至少展示：</p><ul><li>事件标题和来源类型；</li><li>影响金额和影响日期；</li><li>升级原因；</li><li>当前责任人；</li><li>数据状态和计算时间；</li><li>查看依据；</li><li>AI 解释原因；</li><li>与事件类型匹配的处理选项。</li></ul><p>建议排序：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>风险等级降序</span></span>
<span class="line"><span>→ 影响日期升序</span></span>
<span class="line"><span>→ 影响金额降序</span></span>
<span class="line"><span>→ 事件创建时间升序</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_10-真实处理按钮" tabindex="-1">10. 真实处理按钮 <a class="header-anchor" href="#_10-真实处理按钮" aria-label="Permalink to &quot;10. 真实处理按钮&quot;">​</a></h2><p>原型中的“生成动作”和“老板复盘”不进入 MVP。页面必须提供真正改变事件状态的处理按钮。</p><h3 id="_10-1-回款风险事件" tabindex="-1">10.1 回款风险事件 <a class="header-anchor" href="#_10-1-回款风险事件" aria-label="Permalink to &quot;10.1 回款风险事件&quot;">​</a></h3><p>MVP 建议选项：</p><table tabindex="0"><thead><tr><th>选项代码</th><th>页面文案</th><th>需要的补充输入</th></tr></thead><tbody><tr><td><code>escalate_collection</code></td><td>升级催收</td><td>可填写意见</td></tr><tr><td><code>continue_followup</code></td><td>继续负责人跟进</td><td>新截止日期</td></tr><tr><td><code>adjust_expected_date</code></td><td>调整预计到账日期</td><td>新预计到账日期</td></tr><tr><td><code>reassign_owner</code></td><td>调整责任人</td><td>新责任人</td></tr></tbody></table><h3 id="_10-2-付款建议事件" tabindex="-1">10.2 付款建议事件 <a class="header-anchor" href="#_10-2-付款建议事件" aria-label="Permalink to &quot;10.2 付款建议事件&quot;">​</a></h3><p>MVP 建议选项：</p><table tabindex="0"><thead><tr><th>选项代码</th><th>页面文案</th><th>需要的补充输入</th></tr></thead><tbody><tr><td><code>pay_and_fund</code></td><td>同意支付并安排资金</td><td>资金安排说明</td></tr><tr><td><code>defer_payment</code></td><td>延期支付</td><td>新计划日期</td></tr><tr><td><code>adjust_other_expenses</code></td><td>调整其他支出</td><td>可填写调整说明</td></tr><tr><td><code>prioritize_collection</code></td><td>优先催收指定回款</td><td>关联应收或说明</td></tr></tbody></table><p>前端只能展示 <code>allowed_options</code> 中的选项。后端必须再次校验选项是否属于该事件，不能只依赖前端限制。</p><h2 id="_11-决策提交" tabindex="-1">11. 决策提交 <a class="header-anchor" href="#_11-决策提交" aria-label="Permalink to &quot;11. 决策提交&quot;">​</a></h2><p>老板选择处理方案后：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>校验事件仍为 pending</span></span>
<span class="line"><span>→ 校验选项属于 allowed_options</span></span>
<span class="line"><span>→ 校验必填补充输入</span></span>
<span class="line"><span>→ 保存 selected_option、decision_note、decided_by、decided_at</span></span>
<span class="line"><span>→ status 更新为 decided</span></span>
<span class="line"><span>→ 根据选择更新或生成后续任务（MVP 可选）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>使用 <code>version</code> 做乐观锁。同一个事件被两个人同时处理时，后提交者必须收到冲突提示，不得覆盖第一次决定。</p><p>如果 MVP 暂不建设任务执行闭环，至少要完整保存老板选择，不能只在页面本地改变状态。</p><h2 id="_12-查看依据" tabindex="-1">12. 查看依据 <a class="header-anchor" href="#_12-查看依据" aria-label="Permalink to &quot;12. 查看依据&quot;">​</a></h2><p>“查看依据”不调用 AI，直接展示结构化证据：</p><ul><li>来源应收或计划支出；</li><li>应收原金额、已回金额和未回金额；</li><li>支付前后预测余额和现金缺口；</li><li>缺口金额和出现日期；</li><li>命中的规则和规则版本；</li><li>数据批次及计算时间。</li></ul><p>查看依据必须始终可用，即使 AI 未配置或调用失败。</p><h2 id="_13-ai-解释原因" tabindex="-1">13. AI 解释原因 <a class="header-anchor" href="#_13-ai-解释原因" aria-label="Permalink to &quot;13. AI 解释原因&quot;">​</a></h2><p>用户点击“AI 解释原因”时再调用 AI，建议采用 SSE 流式返回：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户点击</span></span>
<span class="line"><span>→ 后端读取事件证据快照</span></span>
<span class="line"><span>→ 拼接固定 Prompt</span></span>
<span class="line"><span>→ AI 生成解释</span></span>
<span class="line"><span>→ SSE 流式返回</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>AI 可以生成：</p><ul><li>一句话结论；</li><li>升级原因说明；</li><li>影响金额和日期说明；</li><li>对 <code>allowed_options</code> 的通俗解释。</li></ul><p>AI 不得：</p><ul><li>重新计算或修改金额和日期；</li><li>增加证据中不存在的事实；</li><li>改变事件风险等级；</li><li>添加 <code>allowed_options</code> 以外的处理方案；</li><li>代替老板提交决定。</li></ul><p>AI 未配置、调用失败或输出校验失败时，使用固定模板解释，不影响查看依据和老板处理事件。</p><h2 id="_14-事件自动关闭" tabindex="-1">14. 事件自动关闭 <a class="header-anchor" href="#_14-事件自动关闭" aria-label="Permalink to &quot;14. 事件自动关闭&quot;">​</a></h2><p>每次数据更新并重新运行规则后，应检查现有 <code>pending</code> 事件：</p><ul><li>应收已经全部回款：关闭回款事件；</li><li>应收不再命中红色升级条件：关闭回款事件；</li><li>付款评估不再是 <code>boss_review</code>：关闭付款事件；</li><li>计划支出已取消：关闭付款事件。</li></ul><p>自动关闭时记录 <code>closed_reason</code>，不得删除事件历史。</p><p>已决定事件不因后续数据变化而改写历史决定；后续变化通过来源数据和新事件体现。</p><h2 id="_15-运行时机" tabindex="-1">15. 运行时机 <a class="header-anchor" href="#_15-运行时机" aria-label="Permalink to &quot;15. 运行时机&quot;">​</a></h2><p>建议在以下场景刷新拍板事件：</p><ul><li>新数据批次发布成功后；</li><li>每日账户余额更新并完成规则重算后；</li><li>应收、实际回款或预计到账日期变化后；</li><li>计划支出或付款评估结果变化后；</li><li>规则版本升级并重新计算后。</li></ul><h2 id="_16-mvp-验收标准" tabindex="-1">16. MVP 验收标准 <a class="header-anchor" href="#_16-mvp-验收标准" aria-label="Permalink to &quot;16. MVP 验收标准&quot;">​</a></h2><ul><li>只接收回款风险和付款建议两个事件来源；</li><li>30 / 60 / 90 天现金流缺口不重复生成独立事件；</li><li>黄色回款风险不进入老板拍板；</li><li>红色回款风险生成且只生成一个未处理事件；</li><li>只有刚性支出导致缺口时生成付款类拍板事件；</li><li>相同来源重复计算不会产生重复未处理事件；</li><li>来源风险解除后，未处理事件自动关闭并保留历史；</li><li>查看依据不依赖 AI；</li><li>AI 只能解释，不可改变计算事实和处理选项；</li><li>老板决定必须持久化，并通过乐观锁避免覆盖。</li></ul><h2 id="_17-待确认口径" tabindex="-1">17. 待确认口径 <a class="header-anchor" href="#_17-待确认口径" aria-label="Permalink to &quot;17. 待确认口径&quot;">​</a></h2><ol><li>回款升级长期采用“逾期 30 天或逾期未回 100 万元”是否合适；</li><li>不同事件类型的标准处理选项和必填输入；</li><li>老板决定后是否在 MVP 自动生成或更新执行任务；</li><li>首页最多展示多少个待拍板事件；</li><li>事件自动关闭后是否需要通知原责任人；</li><li>AI 解释是否缓存及缓存失效规则；</li><li>拍板事件和证据快照的历史保留期限。</li></ol>`,93)])])}const u=e(d,[["render",i]]);export{b as __pageData,u as default};
